import{c as e,Q as a,j as i,m as t}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"出使皮翁比诺的领主阿皮亚","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/upper/49-出使皮翁比诺的领主阿皮亚.md","filePath":"research/machiavelli/machiavelli/diplomatic/upper/49-出使皮翁比诺的领主阿皮亚.md"}'),r={name:"research/machiavelli/machiavelli/diplomatic/upper/49-出使皮翁比诺的领主阿皮亚.md"};function _(c,p,l,o,s,m){return a(),i("div",null,[...p[0]||(p[0]=[t('<h1 id="出使皮翁比诺的领主阿皮亚" tabindex="-1">出使皮翁比诺的领主阿皮亚 <a class="header-anchor" href="#出使皮翁比诺的领主阿皮亚" aria-label="Permalink to &quot;出使皮翁比诺的领主阿皮亚&quot;">​</a></h1><p>出使皮翁比诺的领主阿皮亚诺的亚科波四世</p><p>1504年4月</p><p>执政团决议</p><p>杰出的领主： 我们挑选并派遣尼科洛 · 马基雅维利携带下达给他的国书，出使皮翁 比诺领主大人。对此人的委任在他逗留贵国期间有效。</p><p>委任状</p><p>尼科洛，你要出使至皮翁比诺，见到这位领主，出使的原因我们已经 在这里向你口头交代过了，我们认为那些事情相当重要，你首先要处理那 些与领主大人利益攸关的事情，然后是我们的事情。我们希望能够找到现 实的保全那个邦国的方法；你看到了军队正向锡耶纳前线集结，却没有意 识到其臣民对这位领主的敌意，许多其他的事情通过种种不同的渠道传到 了我们的耳朵里，我们无法对此漠不关心、置若罔闻，而是要尽我们的一 切努力，奋起反抗那些试图进入这个邦国并以任何方式试图改变它的人。 你必须首先非常谦卑地同他谈起此事；然后，你要结识我们已经派到他身 边的那个人，此人在他身边为他提供所需的一切帮助，此外，还能竭尽所 能地在任何方面帮助保全他的邦国；这样一来，你就能通过此人同时得到 两个好处：其一，这位领主会对我们无比忠诚；此外，他在任何事情上都 有求于我们，我们则有求必应，于是，我们就同时既满足了他的需要，又 实现了我们自身的愿望。你在这个邦国逗留期间，要留意观察这位领主的</p><p>①英译本未收入，依据贝尔泰利编校本译出。 ——中译者注</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>秉性特征，还有其臣民的倾向，尤其是支持锡耶纳人和支持我们的不同派 别。你路过坎佩里亚时，可以去见一下我们派驻那个地方的市长，向他询 问相关情况，他一定非常乐意告诉你。</p><p>国 书</p><p>1504年4月2日</p><p>杰出的领主阁下： 持有这份国书的人是我城的公民和国务秘书尼科洛 · 马基雅维利，我 们派遣他出使领主大人是为了向您禀报一些我们认为相当重要的事情。我 们劝勉阁下能够给予他信任，相信他代表我们向您说明的所有情况；我们 希望那些事情能够在目前以及任何其他时候，除了有助于保全您的邦国， 还能够使您感到欣慰。</p><p>尼科洛 · 马基雅维利致佛罗伦萨战场 指挥官多弗 ·斯皮尼的信件</p><p>信件1</p><p>1504年12月14日</p><p>因为他是一名明智的在位者，对各种时机下发生的所有事情都深思熟 虑，甚至是那些令人胆怯的事情，都经过精心准备，使之变得不那么可 怕，在任何危险之下，他都要做到有备无患，我们告诉你得到了这条消 息，并且更进一步地，从不止一个渠道得到的种种迹象使人相信，巴尔托</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>洛梅奥 ·德 · 阿尔维阿诺大人目前还在阿尔维阿诺，他大概集结了250重 骑兵，并给他们新发了军饷，将他们从乡村地区和行动不便的地方悉数 撤了出来，那些地方使许多军事行动耽搁了不少时日，他不惜为此在部 队中引起某种分裂。他寻求使用所有他能采取的手段，除了上述重骑兵 外，我们还发现，他已经命令数量庞大的部队集合； 一直密切监视他能或 者想要做什么,我们判断，如果他这次要夺取这里，他一定要从我城，或 是从我们邻邦巧取某些领土；为了防范他在这一点取得成功，我们对所有 城镇都下达了命令，因为他能经过的任何地方，他都会发现我们的军队较 其他军队更难对付。由于他很可能向佛罗伦萨方向发动进攻，我们将这个 消息告诉你；以使你集合部队听命，采取其他措施，保证我城太平无事。 但如果他计划前来祸害我们的临邦，似乎人们更加担心他会轻而易举地这 么做，我们认为不要忘记预先通知那些邦国，在我们看来，对这些邦国的 拯救不啻拯救我们自己的城邦，在他们中间就有皮翁比诺领主大人。因为 对上述巴尔托洛梅奥而言，他能轻而易举地借着希望率领他的人马进入比 萨的幌子，正如现在他的队伍已经到了这个城的边境，对皮翁比诺发动突 然袭击，而那位领主却缺乏警惕、高枕无忧，丝毫没有准备一个类似的计 划应对；这对我们是不合适的，对那位领主则显得捉襟见肘。为了使得我 们不致疏于对这位领主的责任，以使我们在这件事情上不再感到悔恨，我 们希望无论如何派你告诉他我们的这个担忧，并且你自己也要置于他的指 挥之下，将我们担忧的这件事讲述给他听，并且告诉他我们的这个担忧并 非空穴来风。你要代表我们请求他愿意对他的事情重视起来，并考虑那些 值得信任的人；提醒他最大的敌人是一个自己有邦国的人，凭借自己的军 力武功在那些没有家国的人中树立起赫赫威名。你要将这番话完完全全、 仔仔细细地讲给这位领主听，并表示我们要为他提供我们力所能及的一切 援助，以保全他的邦国；因为，我们这里毫不缺乏合理的或可能的任何手 段。你要竭尽全力让他接受这个安排，然后，马上返回你目前的住处。</p><p>信件2</p><p>1504年12月14日</p><p>你会在这封信件中看到我写给你的关于巴尔托洛梅奥 ·德 · 阿尔维阿 诺的信；其中的内容是千真万确的，据说，他现在所采取行动的方式正如 我在这封信中写给你的那样；因为我们担心，他并不想进入比萨，而是要 攻占皮翁比诺，我们觉得无论是这两种情况的哪一个，我们都会尽其所能 做好防范的准备。至于我们这一方面，我们希望我们的军队能够严阵以待 并补给充分；一旦接到命令，就分发军饷并集合部队，正如你在此前从我 们这里了解到的那样。我们还需要照顾自己的领土，进行一些防卫，而且 要看到固若金汤的坎佩里亚不会在一夜之间从我们眼前被人夺去；当然， 还需要你考虑一下接纳一些人，以免他们成为想要闯进你的领地作奸犯科 的那些人的牺牲品。然而，如果是在皮翁比诺的话，我们希望你能够到这 位领主面前，将我们这封信的内容读给他听，并补充说，你从我们这里得 到了任务，要让他知道我们写给你的信的全部内容，并同他讨论，希望你 能够随机应变向他展示我们的信的内容，以使这位领主能够很好地体会和 考察每一件事情；你要督促他，不要对此掉以轻心，提醒他要睁开眼睛， 重视值得信任的人，我们会按照我们信上所做出的承诺为他提供我们的援 助。你可以一大早前往皮翁比诺，然后当天晚上返回；如果你得到了这位 领主的答复的话，立刻通知我们，不要把我们的信留给他，而只是你给他 读或者让他自己读信的内容；然后，让他还给你，然后你将其带走。你在 此次出使任务中务必要谨慎从事；我们对此抱有良好的祝愿，也深知你是 一位谨慎睿智又干练老成之人。</p>',22)])])}const h=e(r,[["render",_]]);export{d as __pageData,h as default};
